class AuthInterceptor(grpc.ServerInterceptor):
    def __init__(self, secret_token="secure_secret_token_12345"):
        self.secret_token = secret_token
        self.bypass_patterns = [
            r'^/health$',
            r'^/metrics$',
            r'^/admin/.*'
        ]
    
    def _should_bypass_auth(self, method_name):
        for pattern in self.bypass_patterns:
            if re.match(pattern, method_name):
                return True
        return False
    
    def intercept_service(self, continuation, handler_call_details):
        method_name = handler_call_details.method
        
        if self._should_bypass_auth(method_name):
            return continuation(handler_call_details)
        
        metadata = dict(handler_call_details.invocation_metadata)
        auth_token = metadata.get('authorization', '')
        
        if auth_token.startswith('Bearer '):
            token = auth_token[7:]
        else:
            token = auth_token
        
        if token != self.secret_token:
            return grpc.unary_unary_rpc_method_handler(
                lambda request, context: self._deny_access(context),
                request_deserializer=lambda x: x,
                response_serializer=lambda x: x
            )
        
        return continuation(handler_call_details)
    
    def _deny_access(self, context):
        context.abort(StatusCode.UNAUTHENTICATED, 'Invalid or missing authentication token')


class RateLimitInterceptor(grpc.ServerInterceptor):
    def __init__(self, max_requests_per_minute=100):
        self.max_requests = max_requests_per_minute
        self.request_counts = {}
        self.window_start = {}
    
    def intercept_service(self, continuation, handler_call_details):
        metadata = dict(handler_call_details.invocation_metadata)
        client_id = metadata.get('client-id', 'unknown')
        
        current_time = time.time()
        window_duration = 60
        
        if client_id not in self.window_start:
            self.window_start[client_id] = current_time
            self.request_counts[client_id] = 0
        
        if current_time - self.window_start[client_id] > window_duration:
            self.window_start[client_id] = current_time
            self.request_counts[client_id] = 0
        
        self.request_counts[client_id] += 1
        
        if self.request_counts[client_id] > self.max_requests:
            return grpc.unary_unary_rpc_method_handler(
                lambda request, context: self._rate_limit_exceeded(context),
                request_deserializer=lambda x: x,
                response_serializer=lambda x: x
            )
        
        return continuation(handler_call_details)
    
    def _rate_limit_exceeded(self, context):
        context.abort(StatusCode.RESOURCE_EXHAUSTED, 'Rate limit exceeded')


class LoggingInterceptor(grpc.ServerInterceptor):
    def intercept_service(self, continuation, handler_call_details):
        method_name = handler_call_details.method
        print(f"[{time.strftime('%Y-%m-%d %H:%M:%S')}] Incoming request: {method_name}")
        return continuation(handler_call_details)


