def create_secure_server(port=50051, use_tls=True, cert_file=None, key_file=None):
    auth_interceptor = AuthInterceptor()
    rate_limit_interceptor = RateLimitInterceptor(max_requests_per_minute=100)
    logging_interceptor = LoggingInterceptor()
    
    server = grpc.server(
        futures.ThreadPoolExecutor(max_workers=10),
        interceptors=[logging_interceptor, rate_limit_interceptor, auth_interceptor],
        options=[
            ('grpc.max_send_message_length', 50 * 1024 * 1024),
            ('grpc.max_receive_message_length', 50 * 1024 * 1024),
            ('grpc.keepalive_time_ms', 30000),
            ('grpc.keepalive_timeout_ms', 10000),
            ('grpc.http2.max_pings_without_data', 0),
            ('grpc.keepalive_permit_without_calls', 1),
        ]
    )
    
    generic_handler = GenericHandler()
    server.add_generic_rpc_handlers((generic_handler,))
    
    if use_tls and cert_file and key_file:
        with open(key_file, 'rb') as f:
            private_key = f.read()
        with open(cert_file, 'rb') as f:
            certificate_chain = f.read()
        
        server_credentials = grpc.ssl_server_credentials(
            [(private_key, certificate_chain)],
            root_certificates=None,
            require_client_auth=False
        )
        server.add_secure_port(f'[::]:{port}', server_credentials)
        print(f"Secure gRPC server starting on port {port} with TLS")
    else:
        server.add_insecure_port(f'[::]:{port}')
        print(f"gRPC server starting on port {port} (insecure mode)")
    
    return server


